SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_lon_m_loan_request ON sc_lon_m_loan_request CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_lon_m_loan_request() RETURNS trigger AS $BODY$
declare
  li_count integer;
BEGIN
  BEGIN

--insert
if   coalesce(OLD.loan_requestment_no::text, '') = '' then
    select count(1) into STRICT li_count
    from sc_lon_m_loan_request
    where loan_requestment_no = NEW.loan_requestment_no;
    if li_count > 0 then
      CALL spa_dberror('T14:เลขที่คำขอซ้ำ');
    end if;
end if;

  -- ปรุงปรุงทุกครั้งที่บันทึก
  -- if trim(current_setting('app.login_id', true)) is not null then 
  -- night 2020/06/10 
  -- ให้ update ผู้บันทึกทุกกรณีที่มีการแก้ไขผ่านระบบ ยกเว้นการอนุมัติ
--  if trim(current_setting('app.login_id', true)) is not null and :new.approve_status <> '1' then --ตอนอนุมัติ มันได้ 2 น่ะ ไปเช็คมาใหม่ค่ะ
--    :new.entry_id := current_setting('app.login_id', true) ;
--    :new.entry_date := sysdate ;
--    :new.entry_br := current_setting('app.login_br', true) ;
--    
--    spa_dberror(':new.approve_status='||:new.approve_status);
--  end if;
  if coalesce(NEW.requestment_date::text, '') = '' then NEW.requestment_date := pka.today();end if;
  if coalesce(NEW.loan_payment_type_code::text, '') = '' or NEW.loan_payment_type_code = ' '  then NEW.loan_payment_type_code :='01';end if;
  if coalesce(NEW.total_old_loan::text, '') = '' then NEW.total_old_loan := 0;end if;
  if coalesce(NEW.total_oldint::text, '') = '' then NEW.total_oldint := 0;end if;
  if coalesce(NEW.total_share_value::text, '') = '' then NEW.total_share_value := 0;end if;
  if coalesce(NEW.monthdep::text, '') = '' then NEW.monthdep := 0;end if;
  if coalesce(NEW.monthloan::text, '') = '' then NEW.monthloan := 0;end if;
  if coalesce(NEW.monthshare::text, '') = '' then NEW.monthshare := 0;end if;
  if coalesce(NEW.other_amount::text, '') = '' then NEW.other_amount := 0;end if;
  if coalesce(NEW.fee_amount::text, '') = '' then NEW.fee_amount := 0;end if;
  if coalesce(NEW.salary_amount::text, '') = '' then NEW.salary_amount := 0;end if;
  if coalesce(NEW.payint_firstperiod_status::text, '') = '' then NEW.payint_firstperiod_status :='0';end if;
  if coalesce(NEW.req_contract_period::text, '') = '' then NEW.req_contract_period := 0;end if;
  if coalesce(NEW.loan_installment_amount::text, '') = '' then NEW.loan_installment_amount := 0;end if;
  if coalesce(NEW.period_payment_amount::text, '') = '' then NEW.period_payment_amount := 0;end if;
  if coalesce(NEW.last_payment_amount::text, '') = '' then NEW.last_payment_amount := 0;end if;
  if coalesce(NEW.max_loan_permit::text, '') = '' then NEW.max_loan_permit := 0;end if;
  if coalesce(NEW.mem_request_amount::text, '') = '' then NEW.mem_request_amount := 0;end if;
  if coalesce(NEW.loan_request_amount::text, '') = '' then NEW.loan_request_amount := 0;end if;
  if coalesce(NEW.buy_share::text, '') = '' then NEW.buy_share := 0;end if;
  if coalesce(NEW.approve_status::text, '') = '' or NEW.approve_status = ' ' then NEW.approve_status :='2';end if;
  if coalesce(NEW.interest_first::text, '') = '' then NEW.interest_first := 0;end if;
  if coalesce(NEW.atm_status::text, '') = '' or NEW.atm_status = ' ' then NEW.atm_status :='0';end if;
  if coalesce(NEW.document_status::text, '') = '' or NEW.document_status = ' ' then NEW.document_status :='2';end if;
  if coalesce(NEW.document_group::text, '') = '' then NEW.document_group := 0;end if;
  if coalesce(NEW.acc_paid_type::text, '') = '' or NEW.acc_paid_type = ' ' then NEW.acc_paid_type :='0';end if;
  if coalesce(NEW.return_fund_amount::text, '') = '' then NEW.return_fund_amount :=0;end if;
  if coalesce(NEW.flag_status::text, '') = '' or NEW.flag_status = ' ' then NEW.flag_status :='00';end if;
  if coalesce(NEW.cancel_status::text, '') = '' or NEW.cancel_status = ' ' then NEW.cancel_status :='0';end if;
  if coalesce(NEW.document_no::text, '') = '' or NEW.document_no = ' ' then NEW.document_no := '<>';end if;
  if coalesce(NEW.branch_id::text, '') = '' then NEW.branch_id := current_setting('app.login_br', true);end if;

  if OLD.document_status = '2' and NEW.document_status = '1' then
    -- อนุมัติเอกสาร
    NEW.document_pass_date := pka.today(); -- วันที่อนุมัติ
  end if;
  if coalesce(NEW.member_group_no::text, '') = '' or coalesce(trim(both NEW.membership_no)::text, '') = '' then
    BEGIN
      select member_group_no into STRICT NEW.member_group_no 
      from sc_mem_m_membership_registered
      where membership_no = NEW.membership_no;
    exception when others then null;
    end;
  end if;

  if OLD.approve_status != '1' and NEW.approve_status = '1' then 
        NEW.approve_br := current_setting('app.login_br', true);
        NEW.approve_id := current_setting('app.login_id', true);
        NEW.approve_entry := statement_timestamp();
  end if;
  --TGE วันที่รับเงิน  มีไว้ เพื่ออกรายงาน เพราะวันเริ่มสัญญาเปลี่ยน ถ้ามีการมารับเงินก่อน
  if coalesce(NEW.receive_date::text, '') = ''  then NEW.receive_date := NEW.BEGINing_of_contract;end if;

  --Niorn 2024-06-20 MWA 
  if coalesce(NEW.approver_code::text, '') = ''  then NEW.approver_code := '01';end if;

--Niorn 2024-10-21 BOT บันทึกผู้แก้ไขล่าสุด
if pka.isCoop('BOT') = '1' and NEW.cancel_status = '0' then
    NEW.entry_id   := current_setting('app.login_id', true);
    NEW.entry_date := statement_timestamp();
    NEW.entry_br   := current_setting('app.login_br', true);
else
    if coalesce(NEW.entry_id::text, '') = '' then NEW.entry_id := current_setting('app.login_id', true);end if;
    if coalesce(NEW.entry_date::text, '') = '' then NEW.entry_date := statement_timestamp();end if;
    if coalesce(NEW.entry_br::text, '') = '' then NEW.entry_br := current_setting('app.login_br', true);end if;
end if;


  END;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_lon_m_loan_request() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_lon_m_loan_request
	BEFORE INSERT OR UPDATE ON sc_lon_m_loan_request FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_lon_m_loan_request();

